124	
125	  if (ue)
126	    return ((dB_fixed_times10(ue->measurements.rsrp[eNB_index]))/10.0-
127		    get_rx_total_gain_dB(Mod_id,0) -
128		    10*log10(ue->frame_parms.N_RB_DL*12));
129	  return -140.0;
